arguments.argument:
if findTargetX<480 and findTargetY<352
{
  if global.rbSwitchBlueOn=false
  {
    mask_index=sprite_index
    image_alpha=1
  }
  else
  {
    mask_index=sNull
    image_alpha=0.6
  }

  draw_sprite_ext(sprite_index,global.rbSwitchBlueOn,x,y,1,1,0,c_white,image_alpha)
}
